"use client"

import { useState } from "react"
import Link from "next/link"
import { AlertCircle, BarChart3, Zap, HelpCircle } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Card } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import SimulationForm from "@/components/simulations/simulation-form"
import SimulationResults from "@/components/simulations/simulation-results"
import {
  AlertDialog,
  AlertDialogContent,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog"

interface SimulationState {
  isRunning: boolean
  results: any | null
  error: string | null
}

const USAGE_PRESETS = {
  "Typical Lab Device": { idleHours: 2, normalHours: 6, peakHours: 0 },
  "Typical Server": { idleHours: 1, normalHours: 18, peakHours: 5 },
  "Always-On Network Switch": { idleHours: 0, normalHours: 24, peakHours: 0 },
  Custom: { idleHours: 0, normalHours: 0, peakHours: 0 },
}

export default function SimulationsPage() {
  const [simulationState, setSimulationState] = useState<SimulationState>({
    isRunning: false,
    results: null,
    error: null,
  })

  const [tariff, setTariff] = useState<number>(15)
  const [carbonFactor, setCarbonFactor] = useState<number>(0.42)
  const [degradationRate, setDegradationRate] = useState<number>(2)
  const [includeUncertainty, setIncludeUncertainty] = useState<boolean>(true)

  const handleSimulationRun = async (formData: any) => {
    setSimulationState({ isRunning: true, results: null, error: null })

    try {
      const response = await fetch("/api/simulations/calculate", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          deviceA: formData.deviceA,
          deviceB: formData.deviceB,
          tariff,
          carbonFactor,
          degradationRate,
          includeUncertainty,
        }),
      })

      if (!response.ok) {
        throw new Error("Simulation failed")
      }

      const results = await response.json()
      setSimulationState({ isRunning: false, results, error: null })
    } catch (error) {
      setSimulationState({
        isRunning: false,
        results: null,
        error: error instanceof Error ? error.message : "Unknown error",
      })
    }
  }

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <header className="border-b border-border">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Zap className="w-8 h-8 text-primary" />
            <h1 className="text-2xl font-bold text-foreground">Energy Audit</h1>
          </div>
          <nav className="flex gap-4">
            <Link href="/audit">
              <Button variant="ghost">Audit</Button>
            </Link>
            <Link href="/simulations">
              <Button variant="ghost">Simulations</Button>
            </Link>
            <Link href="/dashboard">
              <Button>Dashboard</Button>
            </Link>
          </nav>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Page Title */}
        <div className="mb-8">
          <h2 className="text-3xl font-bold text-foreground mb-2">Device Comparison Simulations</h2>
          <p className="text-muted-foreground">
            Compare two devices based on energy consumption, lifecycle cost, and carbon footprint
          </p>
        </div>

        {/* Simulation Overview Card */}
        <Card className="mb-8 p-6 border border-border">
          <div className="flex gap-4">
            <BarChart3 className="w-6 h-6 text-primary flex-shrink-0 mt-1" />
            <div>
              <h3 className="font-semibold text-foreground mb-2">Simulation Tool Overview</h3>
              <p className="text-sm text-muted-foreground">
                Use this tool to simulate and compare the total cost of ownership, energy consumption, and carbon
                footprint between an existing device and a proposed replacement. The hybrid model factors in device age,
                maintenance costs, and usage patterns to provide confidence-scored results.
              </p>
            </div>
          </div>
          {simulationState.error && (
            <div className="mt-4 p-4 bg-destructive/10 border border-destructive/30 rounded-lg flex gap-2">
              <AlertCircle className="w-5 h-5 text-destructive flex-shrink-0 mt-0.5" />
              <p className="text-sm text-destructive">{simulationState.error}</p>
            </div>
          )}
        </Card>

        {/* Settings Panel */}
        <Card className="mb-8 p-6 border border-border">
          <h3 className="text-lg font-semibold text-foreground mb-6">Simulation Settings</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <div>
              <label className="text-sm font-medium text-foreground flex items-center gap-2 mb-2">
                Electricity Tariff (KSh/kWh)
                <AlertDialog>
                  <AlertDialogTrigger asChild>
                    <button className="text-muted-foreground hover:text-foreground">
                      <HelpCircle className="w-4 h-4" />
                    </button>
                  </AlertDialogTrigger>
                  <AlertDialogContent>
                    <AlertDialogHeader>
                      <AlertDialogTitle>Electricity Tariff</AlertDialogTitle>
                    </AlertDialogHeader>
                    <p className="text-sm text-muted-foreground">
                      Enter the average cost per kilowatt-hour for your electricity provider. This is used to calculate
                      energy costs over the device lifetime.
                    </p>
                  </AlertDialogContent>
                </AlertDialog>
              </label>
              <Input
                type="number"
                value={tariff}
                onChange={(e) => setTariff(Number(e.target.value))}
                placeholder="15"
                min="0"
                step="0.1"
              />
            </div>

            <div>
              <label className="text-sm font-medium text-foreground flex items-center gap-2 mb-2">
                Carbon Factor (kg CO₂/kWh)
                <AlertDialog>
                  <AlertDialogTrigger asChild>
                    <button className="text-muted-foreground hover:text-foreground">
                      <HelpCircle className="w-4 h-4" />
                    </button>
                  </AlertDialogTrigger>
                  <AlertDialogContent>
                    <AlertDialogHeader>
                      <AlertDialogTitle>Carbon Factor</AlertDialogTitle>
                    </AlertDialogHeader>
                    <p className="text-sm text-muted-foreground">
                      Kenya grid average: 0.42 kg CO₂/kWh. Adjust based on your energy mix or specific grid data.
                    </p>
                  </AlertDialogContent>
                </AlertDialog>
              </label>
              <Input
                type="number"
                value={carbonFactor}
                onChange={(e) => setCarbonFactor(Number(e.target.value))}
                placeholder="0.42"
                min="0"
                step="0.01"
              />
            </div>

            <div>
              <label className="text-sm font-medium text-foreground flex items-center gap-2 mb-2">
                Degradation Rate (% per year)
                <AlertDialog>
                  <AlertDialogTrigger asChild>
                    <button className="text-muted-foreground hover:text-foreground">
                      <HelpCircle className="w-4 h-4" />
                    </button>
                  </AlertDialogTrigger>
                  <AlertDialogContent>
                    <AlertDialogHeader>
                      <AlertDialogTitle>Degradation Rate</AlertDialogTitle>
                    </AlertDialogHeader>
                    <p className="text-sm text-muted-foreground">
                      Average performance degradation per year. Default 2% is typical for most computing equipment.
                    </p>
                  </AlertDialogContent>
                </AlertDialog>
              </label>
              <Input
                type="number"
                value={degradationRate}
                onChange={(e) => setDegradationRate(Number(e.target.value))}
                placeholder="2"
                min="0"
                step="0.1"
              />
            </div>

            <div>
              <label className="text-sm font-medium text-foreground flex items-center gap-2 mb-2">
                Include Uncertainty Analysis
              </label>
              <label className="flex items-center gap-2 cursor-pointer">
                <input
                  type="checkbox"
                  checked={includeUncertainty}
                  onChange={(e) => setIncludeUncertainty(e.target.checked)}
                  className="w-4 h-4 rounded border-border"
                />
                <span className="text-sm text-muted-foreground">Enable confidence scoring</span>
              </label>
            </div>
          </div>
        </Card>

        {/* Device Comparison Form */}
        <SimulationForm onRun={handleSimulationRun} isLoading={simulationState.isRunning} presets={USAGE_PRESETS} />

        {/* Results Section */}
        {simulationState.results && (
          <SimulationResults results={simulationState.results} deviceAName="" deviceBName="" />
        )}
      </main>
    </div>
  )
}
